export function parseArgs(argv) {
  const result = { _: [] }
  let index = 0
  while (index < argv.length) {
    const arg = argv[index]
    if (arg === '-' && argv.length > index + 1) {
      index += 2
      result._.push(arg, argv[index - 1])
    } else if (!arg.startsWith('-')) {
      result._.push(arg)
      index += 1
    } else if (arg.includes('=')) {
      const parts = arg.split('=')
      result[parts[0].slice(2)] = parts.slice(1).join('=')
      index += 1
    } else if (argv.length > index + 1 && !argv[index + 1].startsWith('-')) {
      result[arg.slice(2)] = argv[index + 1]
      result._.splice(0, 0, argv[index + 1])
      index += 2
    } else {
      result[arg.slice(2)] = true
      index += 1
    }
  }
  return result
}

